/// Vault rejects mints that touch more than one token name
use aiken/collection/dict
use aiken/fuzz
use cardano/assets.{AssetName, PolicyId}
use aiken/fuzz as cfuzz
use cardano/transaction.{Transaction}
fn single_token_only(tokens: dict.Dict<AssetName, Int>) -> Bool {
  dict.size(tokens) == 1
}

/// The single token must have a non-zero quantity
fn non_zero_qty(tokens: dict.Dict<AssetName, Int>) -> Bool {
  when dict.to_pairs(tokens) is {
    [Pair(_, qty)] -> qty != 0
    _              -> False
  }
}

/// Both guards must pass
fn valid_vault_mint(tokens: dict.Dict<AssetName, Int>) -> Bool {
  single_token_only(tokens) && non_zero_qty(tokens)
}

// ── Validator ────────────────────────────────────────────────────────────────

validator vault_multi_token_guard {
  mint(_redeemer: Data, policy_id: PolicyId, self: Transaction) {
    let minted_tokens = assets.tokens(self.mint, policy_id)
    let only_one = single_token_only(minted_tokens)
    let qty_ok = non_zero_qty(minted_tokens)
    let combined = valid_vault_mint(minted_tokens)
    only_one && qty_ok && combined
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_single_nonzero_valid(
  vals via fuzz.both(cfuzz.asset_name(), fuzz.int_at_least(1)),
) {
  let (name, qty) = vals
  let tokens = dict.empty |> dict.insert(name, qty)
  valid_vault_mint(tokens)
}

test prop_zero_qty_rejected(
  name via cfuzz.asset_name(),
) {
  let tokens = dict.empty |> dict.insert(name, 0)
  !valid_vault_mint(tokens)
}

test prop_empty_rejected() {
  !valid_vault_mint(dict.empty)
}

test prop_two_tokens_rejected() {
  // Two distinct hardcoded names — dict will contain both entries
  let tokens = dict.empty |> dict.insert(#"aa", 1) |> dict.insert(#"bb", 1)
  !single_token_only(tokens)
}

/// Owner can rotate their key: new_commitment = hash(new_owner)
use aiken/crypto.{blake2b_224}
use aiken/fuzz
use aiken/primitive/bytearray
use aiken/fuzz as cfuzz
use cardano/transaction.{Transaction}
fn new_commitment(new_owner: ByteArray) -> ByteArray {
  blake2b_224(new_owner)
}

/// Rotation is valid if old owner authorises AND new commitment is correct
fn rotation_valid(
  old_owner:      ByteArray,
  old_commitment: ByteArray,
  new_owner:      ByteArray,
  new_commitment_: ByteArray,
) -> Bool {
  blake2b_224(old_owner) == old_commitment
    && blake2b_224(new_owner) == new_commitment_
}

pub type VaultDatum {
  owner: ByteArray,
  commitment: ByteArray,
}

pub type VaultRedeemer {
  new_owner: ByteArray,
}

validator param_vault {
  spend(
    datum: Option<VaultDatum>,
    redeemer: VaultRedeemer,
    _ref: Data,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let old_owner = d.owner
    let old_commitment = d.commitment
    let new_owner_ = redeemer.new_owner
    let new_com = new_commitment(new_owner_)
    let signed = list.any(self.extra_signatories, fn(sig) { sig == old_owner })
    let valid_rotation = rotation_valid(old_owner, old_commitment, new_owner_, new_com)
    signed && valid_rotation
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_rotation_valid_with_correct_keys(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.verification_key_hash()),
) {
  let (old_owner, new_owner) = vals
  let old_com = blake2b_224(old_owner)
  let new_com = blake2b_224(new_owner)
  rotation_valid(old_owner, old_com, new_owner, new_com)
}

test prop_wrong_old_owner_fails(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.verification_key_hash()),
) {
  let (old_owner, new_owner) = vals
  let old_com = blake2b_224(old_owner)
  let new_com = blake2b_224(new_owner)
  !rotation_valid(#"deadbeef", old_com, new_owner, new_com)
}

test prop_new_commitment_correct(
  owner via cfuzz.verification_key_hash(),
) {
  new_commitment(owner) == blake2b_224(owner)
}

test prop_different_owners_differ(
  owner via cfuzz.verification_key_hash(),
) {
  // owner vs its hash — almost certainly different lengths, different hashes
  let alt = bytearray.concat(owner, #"ff")
  new_commitment(owner) != new_commitment(alt)
}
